Content.Interface:
FUNCTION_BLOCK RTPP_REG
// Online linear regression: learns correction y = M*x + C
// where x = physics-model RTPP per inverter, y = actual metered power per inverter.
// Call only during uncurtailed, BESS-idle, daytime conditions.
// Outputs M (slope) and C (intercept) used by FB_RTPP to correct RTPP_TOTAL.

VAR_INPUT
	rtpp     : REAL; // Physics-model RTPP per inverter (MW)
	active_p : REAL; // Metered active power per inverter (MW)
END_VAR

VAR_IN_OUT
	M : REAL; // Regression slope (retained global reference)
	C : REAL; // Regression intercept (retained global reference)
END_VAR

VAR_OUTPUT
	N : INT  := 0;   // Current sample count (exposed for SCADA diagnostics)
END_VAR

VAR
	x      : ARRAY[1..1000] OF REAL;
	y      : ARRAY[1..1000] OF REAL;
	sum_w  : REAL := 0;
	sum_x  : REAL := 0;
	sum_y  : REAL := 0;
	sum_xy : REAL := 0;
	sum_x2 : REAL := 0;
	denom  : REAL;
	w      : REAL := 1.0;
	i          : INT;
	writeIndex : INT := 0;
	oldestIndex: INT := 1;
	sampleIndex: INT := 1;
END_VAR

Content.Implementation:
// --- Ring buffer: overwrite oldest sample when full ---
writeIndex := writeIndex + 1;
IF writeIndex > 1000 THEN
	writeIndex := 1;
END_IF

x[writeIndex] := rtpp;
y[writeIndex] := active_p;

IF N < 1000 THEN
	N := N + 1;
END_IF

// --- Regression: require at least 50 samples ---
IF N > 50 THEN
	sum_w  := 0;
	sum_x  := 0;
	sum_y  := 0;
	sum_xy := 0;
	sum_x2 := 0;

	// Determine the oldest sample so regression iterates in chronological order.
	IF N < 1000 THEN
		oldestIndex := 1;
	ELSE
		oldestIndex := writeIndex + 1;
		IF oldestIndex > 1000 THEN
			oldestIndex := 1;
		END_IF
	END_IF

	// Recency weighting: newest sample (index N) has weight 1.0,
	// oldest sample has weight RTPP_Alpha^(N-1). RTPP_Alpha is a global RETAIN
	// variable — adjustable from SCADA or engineering tool at runtime.
	w := EXPT(RTPP_Alpha, INT_TO_REAL(N - 1));

	sampleIndex := oldestIndex;
	FOR i := 1 TO N DO
		sum_w  := sum_w  + w;
		sum_x  := sum_x  + w * x[sampleIndex];
		sum_y  := sum_y  + w * y[sampleIndex];
		sum_xy := sum_xy + w * x[sampleIndex] * y[sampleIndex];
		sum_x2 := sum_x2 + w * x[sampleIndex] * x[sampleIndex];

		IF i < N THEN
			w := w / RTPP_Alpha;
			sampleIndex := sampleIndex + 1;
			IF sampleIndex > 1000 THEN
				sampleIndex := 1;
			END_IF
		END_IF
	END_FOR

	// Denominator guard: avoid divide-by-zero if weighted x values are nearly identical
	denom := sum_w * sum_x2 - sum_x * sum_x;
	IF ABS(denom) > 0.0001 AND sum_w > 0.0001 THEN
		M := (sum_w * sum_xy - sum_x * sum_y) / denom;
		C := (sum_y - M * sum_x) / sum_w;
	END_IF
END_IF
